import uuid
import pytest

def test_create_savings_goal_zero_target_amount_returns_422(auth_headers, api_client):
    payload = {
        "target_amount": 0,
        "target_date": "2026-06-01"
    }
    headers = {**auth_headers, "Idempotency-Key": str(uuid.uuid4())}

    response = api_client.post("/goals", json=payload, headers=headers)

    assert response.status_code == 422
    body = response.json()
    error_text = str(body).lower()
    assert "target_amount" in error_text or "target" in error_text

